#include <stdio.h>
#include <stdlib.h>

#define MAX_NODES 100001

// Use a dynamic adjacency list
int **adj;
int *degree;
int *dist;

void dfs(int node, int par, int d) {
    dist[node] = d;
    for (int i = 0; i < degree[node]; i++) {
        int v = adj[node][i];
        if (v != par) {
            dfs(v, node, d + 1);
        }
    }
}

int main() {
    int n, x, y;

    // Read number of nodes
    if (scanf("%d", &n) != 1 || n < 1 || n > MAX_NODES - 1) {
        fprintf(stderr, "Invalid number of nodes.\n");
        return 1;
    }

    // Allocate memory
    adj = (int **)malloc((n + 1) * sizeof(int *));
    degree = (int *)malloc((n + 1) * sizeof(int));
    dist = (int *)malloc((n + 1) * sizeof(int));

    if (!adj || !degree || !dist) {
        fprintf(stderr, "Memory allocation failed.\n");
        return 1;
    }

    for (int i = 1; i <= n; i++) {
        adj[i] = (int *)malloc(n * sizeof(int)); // Allocate enough space for the maximum possible degree
        degree[i] = 0;
    }

    // Read edges and build adjacency list
    for (int i = 1; i < n; i++) {
        if (scanf("%d %d", &x, &y) != 2 || x < 1 || x > n || y < 1 || y > n) {
            fprintf(stderr, "Invalid edge input.\n");
            return 1;
        }
        adj[x][degree[x]++] = y;
        adj[y][degree[y]++] = x;
    }

    // Perform DFS from node 1
    dfs(1, -1, 0);

    int start_node = 1, maxdist = -1;

    // Find the farthest node from node 1
    for (int i = 1; i <= n; i++) {
        if (dist[i] > maxdist) {
            maxdist = dist[i];
            start_node = i;
        }
    }

    // Perform DFS from the farthest node found
    dfs(start_node, -1, 0);
    maxdist = 0;

    // Find the maximum distance
    for (int i = 1; i <= n; i++) {
        if (dist[i] > maxdist) {
            maxdist = dist[i];
        }
    }

    // Print the result
    printf("%d\n", maxdist);

    // Free allocated memory
    for (int i = 1; i <= n; i++) {
        free(adj[i]);
    }
    free(adj);
    free(degree);
    free(dist);

    return 0;
}

