import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {

    static final int MAX_NODES = 100001;
    static ArrayList<Integer>[] adj;
    static int[] dist;

    static void dfs(int node, int parent, int depth) {
        dist[node] = depth;
        for (int v : adj[node]) {
            if (v != parent) {
                dfs(v, node, depth + 1);
            }
        }
    }

    public static void main(String[] args) throws java.lang.Exception {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();

        // Initialize adjacency list and distance array
        adj = new ArrayList[n + 1];
        dist = new int[n + 1];
        for (int i = 1; i <= n; i++) {
            adj[i] = new ArrayList<>();
        }

        // Read edges and build adjacency list
        for (int i = 1; i < n; i++) {
            int x = scanner.nextInt();
            int y = scanner.nextInt();
            adj[x].add(y);
            adj[y].add(x);
        }

        // Perform DFS from node 1
        dfs(1, -1, 0);

        int startNode = 1;
        int maxDist = -1;

        // Find the farthest node from node 1
        for (int i = 1; i <= n; i++) {
            if (dist[i] > maxDist) {
                maxDist = dist[i];
                startNode = i;
            }
        }

        // Perform DFS from the farthest node found
        dfs(startNode, -1, 0);
        maxDist = 0;

        // Find the maximum distance
        for (int i = 1; i <= n; i++) {
            if (dist[i] > maxDist) {
                maxDist = dist[i];
            }
        }

        // Print the result
        System.out.println(maxDist);
    }
}

