const readline = require('readline');

const N = 100001; 
let adj = Array.from({ length: N }, () => []);
let dist = Array(N).fill(0);

function dfs(node, par, d) {
    dist[node] = d;
    for (const v of adj[node]) {
        if (v !== par) {
            dfs(v, node, d + 1);
        }
    }
}

function main() {
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });

    let n = 0;
    rl.on('line', (line) => {
        if (n === 0) {
            n = parseInt(line.trim());
        } else {
            const [x, y] = line.trim().split(' ').map(Number);
            adj[x].push(y);
            adj[y].push(x);
        }
    });

    rl.on('close', () => {
        dfs(1, 0, 0);

        let startNode = 1;
        let maxDist = -1;

        for (let i = 1; i <= n; i++) {
            if (dist[i] > maxDist) {
                maxDist = dist[i];
                startNode = i;
            }
        }

        dist.fill(0);
        dfs(startNode, 0, 0);

        let diameter = 0;
        for (let i = 1; i <= n; i++) {
            diameter = Math.max(diameter, dist[i]);
        }

        console.log(diameter);
        process.exit(0);
    });
}

